                moves.append(((row, col), (row+2, col+2))) if col < 6 else None
        return moves

    def make_move(self, start_pos, end_pos):
        row_start, col_start = start_pos
        row_end, col_end = end_pos
        if self.board[row_start][col_start] is not None and (row_end, col_end) in [move[1] for move in self.valid_moves((row_start, col_start))]:
            if abs(row_start - row_end) == 2:
                self.board[(row_start + row_end) // 2][(col_start + col_end) // 2] = None
            self.board[row_end][col_end] = self.board[row_start][col_start]
            self.board[row_start][col_start] = None
            if (self.current_player == 'R' and row_end == 0) or (self.current_player == 'B' and row_end == 7):
                self.board[row_end][col_end] = 'K'
            self.current_player = 'B' if self.current_player == 'R' else 'R'

    def check_winner(self):
        red_count = np.sum(self.board == 'R')
        black_count = np.sum(self.board == 'B')
        return 'B wins!' if black_count == 0 else 'R wins!' if red_count == 0 else None

